#include <fstream>
#include <iostream>
using namespace std;

int main() {
 // Create and open file for writing
 ofstream outfile("sample.txt");

 // Check if file opened successfully
 if (!outfile) {
 cout << "Error: Could not open file!" << endl;
 return 1;
 }

 // Write data to file
 outfile << "Hello, File Handling in C++!" << endl;
