#include <fstream>
#include <iostream>
#include <string>
using namespace std;

int main() {
 // Create and open file for reading
 ifstream infile("sample.txt");

 // Check if file opened successfully
 if (!infile.is_open()) {
 cout << "Error: Could not open file!" << endl;
 return 1;
 }

 string line;
 // Read and display file contents
 while (getline(infile, line)) {
 cout << line << endl;
 }

 // Close the file
 infile.close();

 return 0;
}

#include <fstream>
#include <iostream>
using namespace std;

int main() {
 // Open file in append mode
 ofstream outfile;
 outfile.open("log.txt", ios::app);

 if (outfile.fail()) {
 cout << "Failed to open file!" << endl;
 return 1;
 }

 outfile << "New log entry added" << endl;
 outfile.close();

 // Open file in binary mode
 ofstream binfile;
 binfile.open("data.bin", ios::binary | ios::out);

 if (binfile) {
 int num = 42;
 binfile.write(reinterpret_cast<char*>(&num), sizeof(num));
 binfile.close();
 }

 return 0;
}

#include <fstream>
#include <iostream>
using namespace std;

int main() {
 // Open file for both reading and writing
 fstream file("data.txt", ios::in | ios::out | ios::trunc);

 if (!file) {
 cout << "Error opening file!" << endl;
 return 1;
 }

 // Write to file
 file << "First line" << endl;
 file << "Second line" << endl;

 // Clear EOF flag and seek to beginning
 file.clear();
 file.seekg(0, ios::beg);

 // Read from file
 string content;
 while (getline(file, content)) {
 cout << "Read: " << content << endl;
 }

 // Close file
 file.close();

 return 0;
}
